import com.google.common.collect.HashMultimap;
import com.google.common.collect.ImmutableSet;
import com.google.common.collect.Multimap;
import com.google.common.collect.SetMultimap;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Map.Entry;
import java.util.Set;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ACTOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.TUSSENKOMST_MANAGER_KEY;

public class GenereerNeutraliserendeTussenkomst extends AbstractRekenCommand {

    private Set<MoneyKey> bedragTypes;

    private boolean doeActief;

    public GenereerNeutraliserendeTussenkomst(NlpGlobalService service, Set<MoneyKey> bedragTypes) {
        this(true, service, bedragTypes);
    }

    public GenereerNeutraliserendeTussenkomst(NlpGlobalService service) {
        this(false, service, ImmutableSet.of());
    }

    public GenereerNeutraliserendeTussenkomst(boolean doeActief, NlpGlobalService service, Set<MoneyKey> bedragTypes) {
        this.bedragTypes = ImmutableSet.copyOf(bedragTypes);
        this.doeActief = doeActief;
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Integer fiscaalJaar = mainContext.getInteger(FISCAAL_JAAR_KEY);
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonCodeManager loonCodeManager = mainContext.getUnchecked(LOONCODE_MANAGER_KEY);
        String actor = mainContext.getUnchecked(ACTOR_KEY);
        List<RekenHoofd> bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);

        RekenResultatenBeheer rekenResultatenBeheer = new RekenResultatenBeheer();
        List<RekenHoofd> gelockten = bestaanden.stream().filter(t -> t.getRnummer() != null).collect(Collectors.toList());
        List<RekenHoofd> outputs = rekenResultatenBeheer.maakRekenResultaten(mainContext, gelockten, OpslaanNulResultaten.NIET_OPSLAAN);

        MoneyMap<ManueleTussenkomstKey> map = new HashMoneyMap<>();
        SetMultimap<ManueleTussenkomstKey, LocalDateInterval> keyToIntervals = HashMultimap.create();
        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);
        Set<DetectSleutelTussenkomstKey> sleutelTussenkomstVereist = new HashSet<>();
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        Multimap<Opdracht, LocalDateInterval> huidigeElementairePeriodes = HashMultimap.create();
        Set<RekenHoofdKey> huidigeSleutels = new HashSet<>();

        for (Opdracht opdracht : persoon.getOpdrachten()) {
            for (Opper opper : opdracht.getOpperSlices()) {
                huidigeElementairePeriodes.put(opdracht, opper.getActualInterval().overlap(rekenTijd.rekenPeriode));
                huidigeSleutels.add(new RekenHoofdKey(new SleutelGegevensSingleOpper(opper), rekenTijd));
            }
        }
        for (RekenHoofd hoofd : outputs) {
            RekenHoofdKey sleutelKey = new RekenHoofdKey(hoofd);
            if (hoofd.getBeslagDatum() == rekenTijd.beslagDatum) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
                        if ((!huidigeElementairePeriodes.get(hoofd.getOpdracht()).contains(lijn.getPeriode()) || !huidigeSleutels
                                .contains(sleutelKey)) && checkRekenBedrag(rekenBedrag, lijn.getRegimeBv(), hoofd.getBeginDatum())) {
                            sleutelTussenkomstVereist.add(new DetectSleutelTussenkomstKey(hoofd, lijn, rekenBedrag));
                        }
                    }
                }
            }
        }
        for (RekenHoofd hoofd : outputs) {
            if (hoofd.getBeslagDatum() == rekenTijd.beslagDatum) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
                        DetectSleutelTussenkomstKey detectKey = new DetectSleutelTussenkomstKey(hoofd, lijn, rekenBedrag);
                        if (checkRekenBedrag(rekenBedrag, lijn.getRegimeBv(), hoofd.getBeginDatum()) && !sleutelTussenkomstVereist
                                .contains(detectKey)) {
                            ManueleTussenkomstKey key = new ManueleTussenkomstKey(hoofd, lijn, rekenBedrag);
                            map.addToMoney(key, rekenBedrag.getBedrag());
                            ManueleTussenkomstKey intervalKey = new ManueleTussenkomstKey(key, rekenTijd.rekenPeriode);
                            keyToIntervals.put(intervalKey, key.getPeriode());
                        }
                    }
                }
            }
        }

        for (Entry<ManueleTussenkomstKey, Money> entry : map.entrySet()) {
            Money bedrag = entry.getValue();
            if (bedrag.signum() != 0) {
                ManueleTussenkomstKey key = entry.getKey();
                Opper opper = RekenTools.findOpper(key.getOpdracht(), key.getDatum());
                ManueleTussenkomst tussenkomst = maakTussenkomst(key, fiscaalJaar, bedrag, loonCodeManager, actor);
                if (!overgenomenBedragKey(tussenkomst) || fiscaalJaar == rekenTijd.beginDatum.getYear() || !checkSleutelTussenkomst(key,
                        keyToIntervals, rekenTijd)) {
                    tussenkomstManager.addTussenkomst(tussenkomst, opper);
                }
            }
        }
        return CONTINUE_PROCESSING;
    }

    private boolean checkSleutelTussenkomst(
            ManueleTussenkomstKey key, SetMultimap<ManueleTussenkomstKey, LocalDateInterval> keyToIntervals,
            RekenTijd rekenTijd) {
        ManueleTussenkomstKey intervalKey = new ManueleTussenkomstKey(key, rekenTijd.rekenPeriode);
        Set<LocalDateInterval> intervals = keyToIntervals.get(intervalKey);
        List<LocalDateInterval> intervalList = new ArrayList<>(intervals);
        boolean overlap = false;
        for (int index = 0; index < intervalList.size() - 1; index++) {
            LocalDateInterval interval1 = intervalList.get(index);
            for (int index2 = index + 1; index2 < intervalList.size(); index2++) {
                LocalDateInterval interval2 = intervalList.get(index2);
                overlap = interval1.overlaps(interval2);
                if (overlap) {
                    break;
                }
            }
        }
        return overlap;
    }

    private boolean overgenomenBedragKey(ManueleTussenkomst tussenkomst) {
        return tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING
                || tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN
                || tussenkomst.getBedragType() == RekenBedragType.BIJZONDERE_BIJDRAGE
                || tussenkomst.getBedragType() == RekenBedragType.VRIJSTELLING_BELASTBAAR;
    }

    protected boolean checkRekenBedrag(RekenBedrag bedrag, LnedefRegBv regimeBv, LocalDate datum) {
        MoneyKey bedragType = RekenTools.bedragTypeToMoneyKey(bedrag.getBedragType(), regimeBv, datum);
        return bedragTypes.contains(bedragType) || !doeActief;
    }

    private ManueleTussenkomst maakTussenkomst(
            ManueleTussenkomstKey key, Integer fiscaalJaar, Money bedrag, LoonCodeManager loonCodeManager,
            String actor) {
        ManueleTussenkomst tussenkomst = new ManueleTussenkomstPO();
        tussenkomst.setOpdracht(key.getOpdracht());
        tussenkomst.setDatum(key.getDatum());
        AardKodeExtensie looncode = loonCodeManager.getById(key.getAardKodeExtensie().getId());
        tussenkomst.setAardKodeExtensie(looncode);
        tussenkomst.setRegimeBv(key.getRegime());
        tussenkomst.setFunctie(doeActief ? ManueleTussenkomstFunctie.ACTIEF_PLUS : ManueleTussenkomstFunctie.PASSIEF_PLUS);
        tussenkomst.setBedragType(RekenTools.moneyKeyToBedragType(key.getBedragType()));
        if (tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING
                || tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN
                || tussenkomst.getBedragType() == RekenBedragType.BIJZONDERE_BIJDRAGE) {
            tussenkomst.setFiscaalJaar(fiscaalJaar);
        }
        tussenkomst.setBedrag(bedrag.negate());
        tussenkomst.setBron(ManueleTussenkomstBron.NEUTRALISATIE);
        tussenkomst.setVerantwoording("");
        tussenkomst.setActor(actor);
        return tussenkomst;
    }

}
